class Solution {
    public int clumsy(int n) {
        if (n == 1) {
            return 1;
        }
        int result = n;
        for (int i = n - 1; i > 1; i--) {
            if (i % 4 == 1) {
                result *= i;
            } else if (i % 4 == 2) {
                result /= i;
            } else if (i % 4 == 3) {
                result += i;
            } else {
                result -= i;
            }
        }
        return result;
    }
}
```
